  59→        order: vec![pace_key],
  60→        next_pace_seed: "AAB".to_string(),
  61→        paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
  62→        paces,
  63→    };
  64→    (heat_key, heat)
  65→}
