 706→#[test]
 707→fn jjtg_rail_move_first() {
 708→    // Test that --first moves to first ACTIONABLE position, not absolute position 0
 709→    let mut gallops = make_valid_gallops();
 710→    let (heat_key, mut heat) = make_valid_heat("AB", "my-heat");
 711→
 712→    // Make the first pace (from make_valid_heat) complete
 713→    let pace1_key = heat.order[0].clone();
 714→    heat.paces.get_mut(&pace1_key).unwrap().tacks[0].state = jjrg_PaceState::Complete;
 715→
 716→    // Add pace2 (complete) and pace3 (rough) and pace4 (rough)
 717→    let pace2_key = "₢ABAAB".to_string();
 718→    let pace3_key = "₢ABAAC".to_string();
 719→    let pace4_key = "₢ABAAD".to_string();
 720→    heat.paces.insert(pace2_key.clone(), jjrg_Pace {
 721→        tacks: vec![make_valid_tack(jjrg_PaceState::Complete, "second-pace", None)],
 722→    });
 723→    heat.paces.insert(pace3_key.clone(), jjrg_Pace {
 724→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, "third-pace", None)],
 725→    });
 726→    heat.paces.insert(pace4_key.clone(), jjrg_Pace {
 727→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, "fourth-pace", None)],
 728→    });
 729→    heat.order.push(pace2_key.clone());
 730→    heat.order.push(pace3_key.clone());
 731→    heat.order.push(pace4_key.clone());
 732→    heat.next_pace_seed = "AAE".to_string();
 733→
 734→    // Order: [complete1, complete2, rough3, rough4]
 735→    gallops.heats.insert(heat_key.clone(), heat);
 736→
 737→    // Move fourth pace (rough) to first actionable position
 738→    // Should go BEFORE pace3 (first rough), not before pace1 (absolute first)
 739→    let args = jjrg_RailArgs {
 740→        firemark: "AB".to_string(),
 741→        order: vec![],
 742→        move_coronet: Some(pace4_key.clone()),
 743→        before: None,
 744→        after: None,
 745→        first: true,
 746→        last: false,
 747→    };
 748→
 749→    let result = gallops.jjrg_rail(args);
 750→    assert!(result.is_ok());
 751→
 752→    // Expected order: [complete1, complete2, rough4, rough3]
 753→    let heat = gallops.heats.get(&heat_key).unwrap();
 754→    assert_eq!(heat.order[0], pace1_key, "complete1 should stay at index 0");
 755→    assert_eq!(heat.order[1], pace2_key, "complete2 should stay at index 1");
 756→    assert_eq!(heat.order[2], pace4_key, "rough4 should move to first actionable (index 2)");
 757→    assert_eq!(heat.order[3], pace3_key, "rough3 should shift to index 3");
 758→}
